import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";

const Freelancers = () => {
  const navigate = useNavigate();
  const [freelancers, setFreelancers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [messagingSending, setMessagingSending] = useState(null);

  // =====================================
  // FETCH FREELANCERS
  // =====================================
  useEffect(() => {
    const fetchFreelancers = async () => {
      try {
        const res = await API.get("/users/freelancers");
        setFreelancers(res.data);
      } catch (err) {
        console.log(err);
      } finally {
        setLoading(false);
      }
    };
    fetchFreelancers();
  }, []);

  // =====================================
  // MESSAGE FUNCTION
  // ✅ Message அனுப்பிட்டு Messages page-க்கு போகும்
  // =====================================
  const handleMessage = async (freelancer) => {
    setMessagingSending(freelancer.id);
    try {
      // Initial message அனுப்பு
      await API.post("/messages", {
        receiver_id: freelancer.id,
        content: `Hi ${freelancer.name}! I'd like to connect with you.`,
      });
      // Messages page-க்கு navigate பண்ணு
      navigate("/client/messages");
    } catch (err) {
      // Already messaged இருந்தாலும் navigate பண்ணு
      navigate("/client/messages");
    } finally {
      setMessagingSending(null);
    }
  };

  // =====================================
  // INVITE FUNCTION
  // =====================================
  const handleInvite = (freelancer) => {
    alert(`Invitation sent to ${freelancer.name}`);
  };

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-6xl mx-auto">

        {/* HEADER */}
        <div className="mb-6">
          <h1 className="text-2xl font-bold text-gray-800">Browse Freelancers</h1>
          <p className="text-gray-500 mt-1">
            Connect with skilled freelancers for your projects
          </p>
        </div>

        {/* LOADING */}
        {loading && (
          <div className="text-center py-10">
            <div className="w-10 h-10 border-4 border-teal-500 border-t-transparent rounded-full animate-spin mx-auto mb-3"></div>
            <p className="text-gray-500">Loading freelancers...</p>
          </div>
        )}

        {/* EMPTY */}
        {!loading && freelancers.length === 0 && (
          <div className="bg-white rounded-xl p-10 text-center shadow text-gray-400">
            <div className="text-5xl mb-3">👥</div>
            <p>No Freelancers Found</p>
          </div>
        )}

        {/* GRID */}
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {freelancers.map((user) => (
            <div
              key={user.id}
              className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 hover:shadow-md transition"
            >
              {/* PROFILE */}
              <div className="flex items-center gap-4 mb-4">
                <div className="w-12 h-12 bg-teal-500 text-white flex items-center justify-center rounded-full text-lg font-bold flex-shrink-0">
                  {user.name?.charAt(0).toUpperCase()}
                </div>
                <div>
                  <h3 className="font-semibold text-lg text-gray-800">
                    {user.name}
                  </h3>
                  <p className="text-gray-500 text-sm">{user.email}</p>
                  <span className="bg-blue-100 text-blue-600 text-xs px-2 py-0.5 rounded-full font-medium">
                    Freelancer
                  </span>
                </div>
              </div>

              {/* BUTTONS */}
              <div className="flex gap-2 mt-4">

                {/* ✅ MESSAGE BUTTON */}
                <button
                  onClick={() => handleMessage(user)}
                  disabled={messagingSending === user.id}
                  className="flex-1 bg-teal-600 hover:bg-teal-700 text-white py-2 rounded-lg text-sm font-medium transition disabled:opacity-50 flex items-center justify-center gap-1"
                >
                  {messagingSending === user.id ? (
                    "Sending..."
                  ) : (
                    <>💬 Message</>
                  )}
                </button>

                {/* INVITE BUTTON */}
                <button
                  onClick={() => handleInvite(user)}
                  className="flex-1 bg-gray-100 hover:bg-gray-200 text-gray-700 py-2 rounded-lg text-sm font-medium transition"
                >
                  📨 Invite
                </button>

              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Freelancers;
